import urllib.request
import json
import re

TOKEN = "t-g1043smQNCVUF35SXLNGAG7RVRLIIWO3UBTNCXCD"
DOC_ID = "P9qLdk6g7oGO26x3r6ncLHLnnoh"
ROOT_BLOCK_ID = "P9qLdk6g7oGO26x3r6ncLHLnnoh"

def md_to_blocks(md_content):
    """Convert markdown content to Feishu block format."""
    blocks = []
    lines = md_content.split('\n')
    i = 0
    while i < len(lines):
        line = lines[i]

        # Skip horizontal rules and trivial lines
        if line.strip() == '---' or line.strip() == '*本摘要由系统自动生成*' or line.strip() == '':
            i += 1
            continue

        # Heading 1: # 标题
        if line.startswith('# ') and not line.startswith('## '):
            text = line[2:].strip()
            blocks.append({
                "block_type": 4,
                "heading1": {
                    "elements": [{"text_run": {"content": text}}],
                    "style": {"align": 1}
                }
            })
            i += 1
            continue

        # Heading 2: ## 标题
        if line.startswith('## '):
            text = line[3:].strip()
            blocks.append({
                "block_type": 5,
                "heading2": {
                    "elements": [{"text_run": {"content": text}}],
                    "style": {"align": 1}
                }
            })
            i += 1
            continue

        # Heading 3: ### 标题
        if line.startswith('### '):
            text = line[4:].strip()
            blocks.append({
                "block_type": 6,
                "heading3": {
                    "elements": [{"text_run": {"content": text}}],
                    "style": {"align": 1}
                }
            })
            i += 1
            continue

        # List items: - or * or numbered
        if line.strip().startswith('- **') or line.strip().startswith('* **'):
            # Bold list item
            text = line.strip()
            blocks.append({
                "block_type": 2,
                "text": {
                    "elements": [{"text_run": {"content": text, "text_element_style": {"bold": False}}}],
                    "style": {}
                }
            })
            i += 1
            continue

        if line.strip().startswith('- ') or line.strip().startswith('* '):
            text = line.strip()
            blocks.append({
                "block_type": 2,
                "text": {
                    "elements": [{"text_run": {"content": text}}],
                    "style": {}
                }
            })
            i += 1
            continue

        # Checkbox: - [ ] or - [x]
        if re.match(r"^\s*-\s*\[[ xX]\]\s*", line):
            text = line.strip()
            blocks.append({
                "block_type": 2,
                "text": {
                    "elements": [{"text_run": {"content": text}}],
                    "style": {}
                }
            })
            i += 1
            continue

        # Numbered list: 1. 2. etc
        if re.match(r"^\s*\d+\.\s+", line):
            text = line.strip()
            blocks.append({
                "block_type": 2,
                "text": {
                    "elements": [{"text_run": {"content": text}}],
                    "style": {}
                }
            })
            i += 1
            continue

        # Separator lines like "## 📅 基本信息"
        # Just output as text
        text = line.strip()
        if text and text != '':
            blocks.append({
                "block_type": 2,
                "text": {
                    "elements": [{"text_run": {"content": text}}],
                    "style": {}
                }
            })

        i += 1

    return blocks

def append_blocks(blocks, day_name):
    """Append blocks to the document."""
    if not blocks:
        print(f"  [{day_name}] No blocks to append")
        return

    url = f"https://open.feishu.cn/open-apis/docx/v1/documents/{DOC_ID}/blocks/{ROOT_BLOCK_ID}/children"
