def append_text_blocks(doc_token, block_id, texts, token):
    """Append text blocks using the format that works with feishu API."""
    # The format that works: text block with text_run
    blocks = []
    for text in texts:
        blocks.append({
            "block_type": 2,
            "text": {
                "elements": [{"text_run": {"content": text}}],
                "style": {}
            }
        })

    url = f"https://open.feishu.cn/open-apis/docx/v1/documents/{doc_token}/blocks/{block_id}/children"
    data = json.dumps({"children": blocks}, ensure_ascii=False).encode('utf-8')
    req = urllib.request.Request(url, data=data, method='POST', headers={
        'Content-Type': 'application/json',
        'Authorization': f'Bearer {token}'
    })

    with urllib.request.urlopen(req) as resp:
        return json.loads(resp.read())

def append_heading_block(doc_token, block_id, level, text, token):
    """Append a heading block."""
    if level == 1:
        block_type = 4
        key = "heading1"
    elif level == 2:
        block_type = 5
        key = "heading2"
    else:
        block_type = 6
        key = "heading3"

    blocks = [{
        "block_type": block_type,
        key: {
            "elements": [{"text_run": {"content": text}}]
        }
    }]

    url = f"https://open.feishu.cn/open-apis/docx/v1/documents/{doc_token}/blocks/{block_id}/children"
    data = json.dumps({"children": blocks}, ensure_ascii=False).encode('utf-8')
    req = urllib.request.Request(url, data=data, method='POST', headers={
        'Content-Type': 'application/json',
        'Authorization': f'Bearer {token}'
    })

    try:
        with urllib.request.urlopen(req) as resp:
            return json.loads(resp.read())
    except urllib.error.HTTPError as e:
        body = e.read().decode('utf-8')
        return {"code": e.code, "error": body}

def process_file(doc_token, block_id, file_path, token, day_name):
    """Process a single markdown file."""
    with open(file_path, 'r', encoding='utf-8') as f:
        content = f.read()

    lines = content.split('\n')
    texts_batch = []
    total_blocks = 0
    batch_size = 50

    i = 0
    while i < len(lines):
        line = lines[i].rstrip()
        stripped = line.strip()

        # Skip separators and footer
        if stripped == '---' or stripped == '*本摘要由系统自动生成*' or stripped == '':
            i += 1
            continue

        # Heading 1
        if stripped.startswith('# ') and not stripped.startswith('## ') and not stripped.startswith('### '):
            # Flush text batch first
            if texts_batch:
                result = append_text_blocks(doc_token, block_id, texts_batch, token)
                if result.get('code') == 0:
                    total_blocks += len(texts_batch)
                texts_batch = []

            text = stripped[2:]
            result = append_heading_block(doc_token, block_id, 1, text, token)
            if result.get('code') == 0:
                total_blocks += 1
            else:
                print(f"    H1 ERROR: {result}")
            i += 1
            continue

        # Heading 2
        if stripped.startswith('## ') and not stripped.startswith('### '):
            if texts_batch:
                result = append_text_blocks(doc_token, block_id, texts_batch, token)
                if result.get('code') == 0:
                    total_blocks += len(texts_batch)
                texts_batch = []

            text = stripped[3:]
            result = append_heading_block(doc_token, block_id, 2, text, token)
            if result.get('code') == 0:
                total_blocks += 1
            else:
                print(f"    H2 ERROR: {result}")
            i += 1
            continue

        # Heading 3
        if stripped.startswith('### '):
            if texts_batch:
                result = append_text_blocks(doc_token, block_id, texts_batch, token)
                if result.get('code') == 0:
                    total_blocks += len(texts_batch)
                texts_batch = []

            text = stripped[4:]
            result = append_heading_block(doc_token, block_id, 3, text, token)
            if result.get('code') == 0:
                total_blocks += 1
            else:
                print(f"    H3 ERROR: {result}")
            i += 1
            continue

        # Text content - accumulate
        texts_batch.append(stripped)

        # Flush when batch is full
        if len(texts_batch) >= batch_size:
            result = append_text_blocks(doc_token, block_id, texts_batch, token)
            if result.get('code') == 0:
                total_blocks += len(texts_batch)
            else:
                print(f"    TEXT ERROR: {result.get('msg')}")
            texts_batch = []

        i += 1

    # Flush remaining
    if texts_batch:
        result = append_text_blocks(doc_token, block_id, texts_batch, token)
        if result.get('code') == 0:
            total_blocks += len(texts_batch)
        else:
            print(f"    TEXT ERROR: {result.get('msg')}")

    return total_blocks

